---@class LxSprite
local LxSprite = classX("LxSprite", nil)

---@param image Image|SpriteRenderer
function LxSprite:LxSprite(image)
    self._image = image
    self._bEnable = image and image.enabled

    self._path = nil
    self._lastRefPath = nil
    self._isRecycled = false
    self._isGray = false

    self._isNativeSize = false

    self._loadedCallback = nil
    self._loadedCallbackObj = nil
end

function LxSprite:Dispose()
    if self._isDisposed then return end
    if self._lastRefPath then
        local lastRefPath = self._lastRefPath
        self._lastRefPath = nil
        MgrCenter.ComponentMgr:RecycleSprite(lastRefPath)
    end
    table.dispose(self)
    self._isDisposed = true
end

function LxSprite:Enable(bEnable)
    if self._bEnable == bEnable then return end
    self._bEnable = bEnable
    if not self._image then return end
    self._image.enabled = bEnable
end

function LxSprite:Recycle()
    self._isRecycled = true
    if self._lastRefPath then
        self._image.sprite = nil
        local lastRefPath = self._lastRefPath
        self._lastRefPath = nil
        MgrCenter.ComponentMgr:RecycleSprite(lastRefPath)
    end
    self._backEnabled = self._bEnable
    self:Enable(false)
end

function LxSprite:WarmUp()
    self._isRecycled = false
    if self._backEnabled then
        self:Enable(true)
    end
end

---记录最后引用atlas的路径
function LxSprite:RecordLastRefPath(path)
    local lastRefPath = self._lastRefPath
    self._lastRefPath = path
    if lastRefPath then
        MgrCenter.ComponentMgr:RecycleSprite(lastRefPath)
    end
end

function LxSprite:SetSprite(path, isNativeSize, isHideLoad, isCountSize)
    self._path = path

    if not self._image then return end

    if not self._image.sprite and nil == isHideLoad then
        isHideLoad = true
    end

    self._isNativeSize = isNativeSize
    self._isHideLoad = isHideLoad
    self._isCountSize = isCountSize

    if string.isempty(self._path) then return end

    if self._isHideLoad then
        self:Enable(false)
    end


    MgrCenter.ComponentMgr:RequestSprite(path, self.OnSpriteLoaded, self)
end

function LxSprite:OnSpriteLoaded(sprite, requestPath)
    if self._isDisposed or self._isRecycled then return false end
    if requestPath ~= self._path then return false end
    if not CS.IsValidObject(self._image) then return false end
    
    self._image.sprite = sprite

    self:RecordLastRefPath(requestPath)

    if self._isNativeSize then
        self._image:SetNativeSize()
    end
    if not self._bEnable then
        self:Enable(true)
    end

    if self._isLoadedShow then
        CS.ShowObject(self._image.gameObject, true)
    end

    if CS.IsWebGL() and self._isCountSize then
        LxUiHelper.SetImageSizeScale(self._image)
    end

    local cb = self._loadedCallback
    local cbObj = self._loadedCallbackObj
    self._loadedCallbackObj = nil
    self._loadedCallback = nil
    if cb ~= nil then
        if cbObj ~= nil then
            cb(cbObj, self)
        else
            cb(self)
        end
    end

    return true
end

function LxSprite:SetGray(bVal)
    if self._isGray == bVal then return end
    self._isGray = bVal
    if not bVal then
        self._image.material = nil
        return
    end
    local matName = "ui_gray"
    if (not self._image.material or self._image.material.name ~= matName) then
        self._image.material = LxResUtil.GetUiGrayMaterial()
    end
end

function LxSprite:SetLoadedCallback(method, methodObj)
    self._loadedCallback = method
    self._loadedCallbackObj = methodObj
end

return LxSprite